+            (Ok(value), Ok(())) => Ok(value),
+            (Ok(_), Err(end_err)) => Err(end_err),
+            (Err(op_err), Ok(())) => Err(op_err),
+            (Err(op_err), Err(end_err)) => {
+                warn!(?op, error = %end_err, "request scope cleanup failed after operation error");
+                Err(op_err)
+            }
